def _upsert_family(cur, seed):
    vals=(seed['family_name'], normalize_key(seed['family_name']), seed.get('family_class'), seed.get('transformation_type'), seed.get('mechanism_type'), seed.get('reactant_pattern_text'), seed.get('product_pattern_text'), seed.get('key_reagents_clue'), seed.get('common_solvents'), seed.get('common_conditions'), seed.get('synonym_names'), seed.get('description_short'), seed.get('overview_count',0), seed.get('application_count',0), seed.get('mechanism_count',0), 'chemlens_backend_db_schema_frontmatter_batch9_patch_20260411.zip', FRONTMATTER_BATCH9_VERSION)
    cur.execute("""
    INSERT INTO reaction_family_patterns (
      family_name,family_name_norm,family_class,transformation_type,mechanism_type,reactant_pattern_text,product_pattern_text,
      key_reagents_clue,common_solvents,common_conditions,synonym_names,description_short,overview_count,application_count,mechanism_count,
      latest_source_zip,seeded_from,latest_updated_at,created_at,updated_at
    ) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,datetime('now'),datetime('now'),datetime('now'))
    ON CONFLICT(family_name_norm) DO UPDATE SET
      family_name=excluded.family_name,family_class=excluded.family_class,transformation_type=excluded.transformation_type,
      mechanism_type=excluded.mechanism_type,reactant_pattern_text=excluded.reactant_pattern_text,product_pattern_text=excluded.product_pattern_text,
      key_reagents_clue=excluded.key_reagents_clue,common_solvents=excluded.common_solvents,common_conditions=excluded.common_conditions,
      synonym_names=excluded.synonym_names,description_short=excluded.description_short,
      overview_count=MAX(reaction_family_patterns.overview_count, excluded.overview_count),
      application_count=MAX(reaction_family_patterns.application_count, excluded.application_count),
      mechanism_count=MAX(reaction_family_patterns.mechanism_count, excluded.mechanism_count),
      latest_source_zip=excluded.latest_source_zip,seeded_from=excluded.seeded_from,latest_updated_at=datetime('now'),updated_at=datetime('now')
    """, vals)

def apply_frontmatter_batch9(db_path: str | Path) -> Dict[str, Any]:
    db_path = str(db_path)
    ensure_frontmatter_schema(db_path)
    conn = sqlite3.connect(db_path)
    cur = conn.cursor()
    for seed in FAMILY_PATTERN_SEEDS:
        _upsert_family(cur, seed)
    page_ids={}
    for seed in PAGE_KNOWLEDGE_SEEDS:
        cur.execute("""
        INSERT INTO manual_page_knowledge (source_label,page_label,page_no,title,section_name,page_kind,summary,family_names,reference_family_name,notes,image_filename,created_at,updated_at)
        VALUES (?,?,?,?,?,?,?,?,?,?,?,datetime('now'),datetime('now'))
        ON CONFLICT(source_label,page_label) DO UPDATE SET
          page_no=excluded.page_no,title=excluded.title,section_name=excluded.section_name,page_kind=excluded.page_kind,summary=excluded.summary,
          family_names=excluded.family_names,reference_family_name=excluded.reference_family_name,notes=excluded.notes,image_filename=excluded.image_filename,updated_at=datetime('now')
        """, (seed['source_label'],seed['page_label'],seed['page_no'],seed['title'],seed['section_name'],seed['page_kind'],seed['summary'],seed['family_names'],seed['reference_family_name'],seed['notes'],seed['image_filename']))
        cur.execute('SELECT id FROM manual_page_knowledge WHERE source_label=? AND page_label=?', (seed['source_label'], seed['page_label']))
        page_ids[seed['page_label']] = cur.fetchone()[0]
    for seed in CURATED_BATCH9_ABBREVIATIONS:
        can_norm=normalize_key(seed['canonical_name']) if seed.get('canonical_name') else None
        cur.execute("""
        INSERT INTO abbreviation_aliases (alias,alias_norm,canonical_name,canonical_name_norm,entity_type,source_label,source_page,confidence,created_at,updated_at)
        VALUES (?,?,?,?,?,?,?,0.92,datetime('now'),datetime('now'))
        ON CONFLICT(alias_norm, canonical_name_norm, entity_type) DO UPDATE SET source_label=excluded.source_label, source_page=excluded.source_page, updated_at=datetime('now')
        """, (seed['alias'], normalize_key(seed['alias']), seed['canonical_name'], can_norm, seed['entity_type'], 'named_reactions_frontmatter_batch9', seed['source_page']))
    for seed in PAGE_ENTITY_SEEDS:
        pid=page_ids[seed['page_label']]
        cur.execute("""
        INSERT INTO manual_page_entities (page_knowledge_id,entity_text,entity_text_norm,canonical_name,entity_type,alias_id,family_name,notes,confidence,created_at,updated_at)
        VALUES (?,?,?,?,?,?,?,?,?,datetime('now'),datetime('now'))
        ON CONFLICT(page_knowledge_id, entity_text_norm, entity_type) DO UPDATE SET
          canonical_name=excluded.canonical_name,family_name=excluded.family_name,notes=excluded.notes,confidence=excluded.confidence,updated_at=datetime('now')
        """, (pid, seed['entity_text'], normalize_key(seed['entity_text']), seed.get('canonical_name'), seed['entity_type'], None, seed.get('family_name'), seed.get('notes'), seed.get('confidence',0.9)))
    conn.commit()
    res={
      'manual_page_knowledge': cur.execute('SELECT COUNT(*) FROM manual_page_knowledge').fetchone()[0],
      'manual_page_entities': cur.execute('SELECT COUNT(*) FROM manual_page_entities').fetchone()[0],
      'abbreviation_aliases': cur.execute('SELECT COUNT(*) FROM abbreviation_aliases').fetchone()[0],
      'reaction_family_patterns': cur.execute('SELECT COUNT(*) FROM reaction_family_patterns').fetchone()[0],
      'batch9_pages': cur.execute("SELECT COUNT(*) FROM manual_page_knowledge WHERE source_label='named_reactions_frontmatter_batch9'").fetchone()[0],
    }
    conn.close(); return res

